previewCss:
.darma-loader-stacked-bars {
  display: grid;
  gap: 7px;
  width: 84px;
  color: var(--loader-color, #6366f1);
}
.darma-loader-stacked-bars b {
  display: block;
  height: 10px;
  border-radius: 999px;
  background: currentColor;
  animation: darma-loader-stacked-bars-stack 1s ease-in-out infinite;
}
.darma-loader-stacked-bars b:nth-child(2) { animation-delay: 0.16s; }
.darma-loader-stacked-bars b:nth-child(3) { animation-delay: 0.32s; }
@keyframes darma-loader-stacked-bars-stack {
  0%, 100% { transform: scaleX(0.38); opacity: 0.38; }
  50% { transform: scaleX(1); opacity: 1; }
}

